use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Pfad zur PDF-Datei
my $pdf_file = 'example.pdf';

# PDF-Datei öffnen
my $pdf = PDF::API2->open($pdf_file);

# Text aus der PDF-Datei extrahieren
my $text = PDF::Text::Simple->new($pdf)->text;

# Suchbegriffe definieren
my %search_terms = (
    date => qr/\b\d{1,2} \w{3} \d{4}\b/, # Beispiel, gesuche nach Datum im Format 21 Sep 2021
    author => qr/Author: \w+ \w+/,       # Beispiel, gesuche nach Autor
    table => qr/\b\d+\.\s+\w+\s+\w+\s+\w+\s+\d+\.\d+\s+\d+\.\d+\b/, # Beispiel, gesuche nach Tabelle
);

# Suchbegriffe in Text ausführen und Ergebnisse ausgeben
foreach my $term (keys %search_terms) {
    if ($text =~ /$search_terms{$term}/i) {
        print "Found $term: $&\n";
    } else {
        print "No $term found.\n";
    }
}
```

